// SumAbsoluteAndFormat computes the sum of absolute values of non-zero elements in numbers.
// If includeDetails is true, it also builds a comma-separated string: positive values as "n,", negative as "(n),".
// label, if non-empty, is prepended as "label: " to that string.
// Returns an error when the sum is zero.
func SumAbsoluteAndFormat(numbers []int, label string, includeDetails bool) (int, string, error) {
	sum, parts := sumAbsoluteAndCollectParts(numbers, includeDetails)
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	s := joinParts(parts)
	if label != "" {
		s = label + ": " + s
	}
	return sum, s, nil
}

// sumAbsoluteAndCollectParts returns the sum of absolute values and, when includeDetails is true,
// a slice of formatted parts: "%d" for positive, "(%d)" for negative, in iteration order.
func sumAbsoluteAndCollectParts(numbers []int, includeDetails bool) (int, []string) {
	var sum int
	var parts []string
	for _, n := range numbers {
		if n > 0 {
			sum += n
			if includeDetails {
				parts = append(parts, fmt.Sprintf("%d", n))
			}
		} else if n < 0 {
			sum -= n
			if includeDetails {
				parts = append(parts, fmt.Sprintf("(%d)", n))
			}
		}
	}
	return sum, parts
}

// joinParts concatenates each part with a trailing comma, matching the original format (e.g. "1,2,(-3),").
func joinParts(parts []string) string {
	var s string
	for _, p := range parts {
		s += p + ","
	}
	return s
}

// SumSignedValues computes the sum of absolute values of non-zero elements in values.
// If formatOutput is true, it also builds a human-readable string: positive numbers as "n,"
// and negative numbers as "(n),". If label is non-empty, it is prepended to that string.
// Returns an error when the computed sum is zero.
func SumSignedValues(values []int, label string, formatOutput bool) (int, string, error) {
	sum := sumAbsoluteValues(values)
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	formatted := ""
	if formatOutput {
		formatted = formatValuesWithSign(values)
		if label != "" {
			formatted = label + ": " + formatted
		}
	}
	return sum, formatted, nil
}

func sumAbsoluteValues(values []int) int {
	var sum int
	for _, v := range values {
		if v > 0 {
			sum += v
		} else if v < 0 {
			sum -= v // same as sum += -v, i.e. absolute value
		}
	}
	return sum
}

func formatValuesWithSign(values []int) string {
	var b strings.Builder
	for _, v := range values {
		if v > 0 {
			b.WriteString(fmt.Sprintf("%d,", v))
		} else if v < 0 {
			b.WriteString(fmt.Sprintf("(%d),", v))
		}
	}
	return b.String()
}
